ptcs-chart-pie {
  padding: 10px !important;
  min-width: 100px !important;
  min-height: 100px !important;
}
ptcs-chart-pie::part(chart-layout) {
  padding-top: 5px !important;
  padding-left: 5px !important;
  padding-bottom: 5px !important;
  padding-right: 5px !important;
}


.qtip-content{ /*tooltip in pie chart on MS,MHR screen*/
    font-size:20px !important;
    color : #3e3e3e !important;
    background-color : #d5d5d5 !important;
    padding-top : 5px !important;
    padding-bottom :  10px !important;
    padding-left : 10px !important;
    padding-right : 10px !important;
    line-height : 34px !important;
}
#tiptip_content { /* tooltip in grid  */
    font-size: 20px !important;
    background: #d5d5d5 !important;
    color : #3e3e3e !important;
    border-color: #d5d5d5 !important;
    border: none !important;
    text-shadow: none !important;
    line-height : 34px !important;
}
.TitleLine {
    background-color: #3e3e3e !important;
    color : #3e3e3e !important
}
.TitleLine .widget-content {
    background :  #3e3e3e !important;
    color : #3e3e3e !important
}
.titleLine {
    background-color: #3e3e3e !important;
    color : #3e3e3e !important
}
ptcs-tooltip-overlay#ptcs-tooltip-overlay {
    content-visibility: auto !important;
}

ptcs-focus-overlay {
	visibility: hidden;
}

.ptcs-wrapper:not([no-wc-style]):focus:not(.dummy):not(.dummy):not(.dummy) { 
    /* box-shadow: inset 0 0 0 1px #eff0f3; */ 
    box-shadow: none; 
}

